import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  Typography,
  IconButton,
  Stack,
  CircularProgress,
  LinearProgress,
  Chip,
  Switch,
  FormControlLabel,
} from '@mui/material';
import {
  DarkMode as DarkModeIcon,
  LightMode as LightModeIcon,
  Memory as MemoryIcon,
  Storage as StorageIcon,
  Speed as SpeedIcon,
  CloudSync as CloudSyncIcon,
  DnsOutlined as DnsIcon,
  PowerSettingsNew as PowerIcon,
  Refresh as RefreshIcon,
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import { getSystemInfo, getServiceStatus, updateServiceStatus, getSubscriptionInfo } from '../services/api';
import { getCommonStyles } from '../styles/commonStyles';

const Dashboard = ({ mode, setMode }) => {
  const theme = useTheme();
  const styles = getCommonStyles(theme);
  const [loading, setLoading] = useState(false);
  const [systemInfo, setSystemInfo] = useState({
    hostname: '',
    platform: '',
    arch: '',
    uptime: 0,
    cpu_usage: 0,
    memory_total: 0,
    memory_used: 0,
  });
  const [serviceStatus, setServiceStatus] = useState({
    singbox: {
      running: false,
      version: '',
    },
    mosdns: {
      running: false,
      version: '',
    },
  });
  const [subscriptionInfo, setSubscriptionInfo] = useState({
    url: '',
    last_update: '',
    next_update: '',
    node_count: 0,
    active_nodes: 0,
  });

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 5000); // 每5秒更新一次
    return () => clearInterval(interval);
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [sysInfo, svcStatus, subInfo] = await Promise.all([
        getSystemInfo(),
        getServiceStatus(),
        getSubscriptionInfo(),
      ]);
      setSystemInfo(sysInfo);
      setServiceStatus(svcStatus);
      setSubscriptionInfo(subInfo);
    } catch (error) {
      console.error('Failed to fetch data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleServiceToggle = async (service, status) => {
    try {
      setLoading(true);
      await updateServiceStatus(service, !status);
      await fetchData();
    } catch (error) {
      console.error(`Failed to toggle ${service}:`, error);
    } finally {
      setLoading(false);
    }
  };

  const formatBytes = (bytes) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return `${parseFloat((bytes / Math.pow(k, i)).toFixed(2))} ${sizes[i]}`;
  };

  const formatUptime = (seconds) => {
    const days = Math.floor(seconds / (24 * 60 * 60));
    const hours = Math.floor((seconds % (24 * 60 * 60)) / (60 * 60));
    const minutes = Math.floor((seconds % (60 * 60)) / 60);
    return `${days}天 ${hours}小时 ${minutes}分钟`;
  };

  const formatDate = (dateString) => {
    if (!dateString) return '-';
    const date = new Date(dateString);
    return date.toLocaleString('zh-CN', {
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
    });
  };

  return (
    <Box>
      {loading && <LinearProgress sx={{ mb: 1 }} />}

      {/* First Row: System Information */}
      <Grid container spacing={1.5} sx={{ mb: 1.5 }}>
        {/* System Info */}
        <Grid item xs={12} md={4}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <StorageIcon color="primary" />
                  <Typography variant="h6">系统信息</Typography>
                </Stack>
                <Stack spacing={1}>
                  <Typography variant="body2">
                    主机名：{systemInfo.hostname}
                  </Typography>
                  <Typography variant="body2">
                    平台：{systemInfo.platform} ({systemInfo.arch})
                  </Typography>
                  <Typography variant="body2">
                    运行时间：{formatUptime(systemInfo.uptime)}
                  </Typography>
                </Stack>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* CPU Usage */}
        <Grid item xs={12} md={4}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <SpeedIcon color="primary" />
                  <Typography variant="h6">CPU 使用率</Typography>
                </Stack>
                <Box sx={{ position: 'relative', display: 'inline-flex', width: '100%', justifyContent: 'center' }}>
                  <CircularProgress
                    variant="determinate"
                    value={systemInfo.cpu_usage}
                    size={120}
                    thickness={4}
                    sx={{
                      color: theme.palette.mode === 'dark' ? 'primary.light' : 'primary.main',
                    }}
                  />
                  <Box
                    sx={{
                      top: 0,
                      left: 0,
                      bottom: 0,
                      right: 0,
                      position: 'absolute',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                    }}
                  >
                    <Typography variant="h4" component="div" color="text.secondary">
                      {`${Math.round(systemInfo.cpu_usage)}%`}
                    </Typography>
                  </Box>
                </Box>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* Memory Usage */}
        <Grid item xs={12} md={4}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <MemoryIcon color="primary" />
                  <Typography variant="h6">内存使用率</Typography>
                </Stack>
                <Box sx={{ position: 'relative', display: 'inline-flex', width: '100%', justifyContent: 'center' }}>
                  <CircularProgress
                    variant="determinate"
                    value={(systemInfo.memory_used / systemInfo.memory_total) * 100}
                    size={120}
                    thickness={4}
                    sx={{
                      color: theme.palette.mode === 'dark' ? 'primary.light' : 'primary.main',
                    }}
                  />
                  <Box
                    sx={{
                      top: 0,
                      left: 0,
                      bottom: 0,
                      right: 0,
                      position: 'absolute',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                    }}
                  >
                    <Typography variant="h4" component="div" color="text.secondary">
                      {`${Math.round((systemInfo.memory_used / systemInfo.memory_total) * 100)}%`}
                    </Typography>
                  </Box>
                </Box>
                <Typography variant="body2" color="text.secondary" align="center">
                  {`${formatBytes(systemInfo.memory_used)} / ${formatBytes(systemInfo.memory_total)}`}
                </Typography>
              </Stack>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      {/* Second Row: Service Status */}
      <Grid container spacing={1.5} sx={{ mb: 1.5 }}>
        {/* Singbox Status */}
        <Grid item xs={12} md={4}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Stack direction="row" alignItems="center" justifyContent="space-between">
                  <Stack direction="row" alignItems="center" spacing={1}>
                    <PowerIcon color="primary" />
                    <Typography variant="h6">Singbox 状态</Typography>
                  </Stack>
                  <FormControlLabel
                    control={
                      <Switch
                        checked={serviceStatus.singbox.running}
                        onChange={() => handleServiceToggle('singbox', serviceStatus.singbox.running)}
                        color="primary"
                      />
                    }
                    label=""
                  />
                </Stack>
                <Stack spacing={1}>
                  <Stack direction="row" justifyContent="space-between" alignItems="center">
                    <Typography variant="body2">运行状态</Typography>
                    <Chip
                      label={serviceStatus.singbox.running ? "运行中" : "已停止"}
                      size="small"
                      sx={serviceStatus.singbox.running ? styles.chip.success : styles.chip.error}
                    />
                  </Stack>
                  <Stack direction="row" justifyContent="space-between" alignItems="center">
                    <Typography variant="body2">版本</Typography>
                    <Typography variant="body2">{serviceStatus.singbox.version || '-'}</Typography>
                  </Stack>
                </Stack>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* Mosdns Status */}
        <Grid item xs={12} md={4}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Stack direction="row" alignItems="center" justifyContent="space-between">
                  <Stack direction="row" alignItems="center" spacing={1}>
                    <DnsIcon color="primary" />
                    <Typography variant="h6">Mosdns 状态</Typography>
                  </Stack>
                  <FormControlLabel
                    control={
                      <Switch
                        checked={serviceStatus.mosdns.running}
                        onChange={() => handleServiceToggle('mosdns', serviceStatus.mosdns.running)}
                        color="primary"
                      />
                    }
                    label=""
                  />
                </Stack>
                <Stack spacing={1}>
                  <Stack direction="row" justifyContent="space-between" alignItems="center">
                    <Typography variant="body2">运行状态</Typography>
                    <Chip
                      label={serviceStatus.mosdns.running ? "运行中" : "已停止"}
                      size="small"
                      sx={serviceStatus.mosdns.running ? styles.chip.success : styles.chip.error}
                    />
                  </Stack>
                  <Stack direction="row" justifyContent="space-between" alignItems="center">
                    <Typography variant="body2">版本</Typography>
                    <Typography variant="body2">{serviceStatus.mosdns.version || '-'}</Typography>
                  </Stack>
                </Stack>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* Service Control */}
        <Grid item xs={12} md={4}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <PowerIcon color="primary" />
                  <Typography variant="h6">服务开关</Typography>
                </Stack>
                <Stack spacing={1}>
                  <FormControlLabel
                    control={
                      <Switch
                        checked={serviceStatus.singbox.running}
                        onChange={() => handleServiceToggle('singbox', serviceStatus.singbox.running)}
                        color="primary"
                      />
                    }
                    label="Singbox 服务"
                  />
                  <FormControlLabel
                    control={
                      <Switch
                        checked={serviceStatus.mosdns.running}
                        onChange={() => handleServiceToggle('mosdns', serviceStatus.mosdns.running)}
                        color="primary"
                      />
                    }
                    label="Mosdns 服务"
                  />
                </Stack>
              </Stack>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      {/* Third Row: Subscription Info */}
      <Grid container spacing={1.5}>
        <Grid item xs={12}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Stack direction="row" alignItems="center" justifyContent="space-between">
                  <Stack direction="row" alignItems="center" spacing={1}>
                    <CloudSyncIcon color="primary" />
                    <Typography variant="h6">订阅信息</Typography>
                  </Stack>
                  <IconButton
                    size="small"
                    onClick={fetchData}
                    sx={{
                      color: 'text.secondary',
                      '&:hover': {
                        color: 'primary.main',
                        backgroundColor: 'action.hover',
                      },
                    }}
                  >
                    <RefreshIcon fontSize="small" />
                  </IconButton>
                </Stack>
                <Grid container spacing={2}>
                  <Grid item xs={12} md={6}>
                    <Stack spacing={1}>
                      <Stack direction="row" justifyContent="space-between" alignItems="center">
                        <Typography variant="body2">订阅地址</Typography>
                        <Typography variant="body2" sx={{ maxWidth: '60%', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                          {subscriptionInfo.url || '-'}
                        </Typography>
                      </Stack>
                      <Stack direction="row" justifyContent="space-between" alignItems="center">
                        <Typography variant="body2">上次更新</Typography>
                        <Typography variant="body2">{formatDate(subscriptionInfo.last_update)}</Typography>
                      </Stack>
                      <Stack direction="row" justifyContent="space-between" alignItems="center">
                        <Typography variant="body2">下次更新</Typography>
                        <Typography variant="body2">{formatDate(subscriptionInfo.next_update)}</Typography>
                      </Stack>
                    </Stack>
                  </Grid>
                  <Grid item xs={12} md={6}>
                    <Stack spacing={1}>
                      <Stack direction="row" justifyContent="space-between" alignItems="center">
                        <Typography variant="body2">节点总数</Typography>
                        <Typography variant="body2">{subscriptionInfo.node_count || 0}</Typography>
                      </Stack>
                      <Stack direction="row" justifyContent="space-between" alignItems="center">
                        <Typography variant="body2">活跃节点</Typography>
                        <Typography variant="body2">{subscriptionInfo.active_nodes || 0}</Typography>
                      </Stack>
                      <Stack direction="row" justifyContent="space-between" alignItems="center">
                        <Typography variant="body2">可用率</Typography>
                        <Typography variant="body2">
                          {subscriptionInfo.node_count
                            ? `${Math.round((subscriptionInfo.active_nodes / subscriptionInfo.node_count) * 100)}%`
                            : '0%'}
                        </Typography>
                      </Stack>
                    </Stack>
                  </Grid>
                </Grid>
              </Stack>
            </CardContent>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );
};

export default Dashboard;
